-- ================================================================
-- WUCC eVoting Seed Data
--
-- Setup order:
--   1. Run supabase/reset_wucc_evoting.sql
--   2. Run this file: supabase/seed.sql
--   3. Create Supabase Auth users for admins as needed
--   4. Insert matching public.profiles rows for admin users
--
-- This seed is intentionally self-contained and uses only the current
-- election statuses: inactive, standby, active, ended, finalized.
-- Password hashes for seeded voters are generated by the voters table
-- trigger in reset_wucc_evoting.sql. That trigger uses schema-safe
-- pgcrypto wrappers and `gen_salt('md5')` for academic/demo stability,
-- so default voter passwords remain each voter's matric number.
-- ================================================================

begin;

create extension if not exists pgcrypto;

do $$
begin
  if to_regclass('public.elections') is null
    or to_regclass('public.positions') is null
    or to_regclass('public.voters') is null
    or to_regclass('public.candidate_applications') is null
    or to_regclass('public.candidates') is null
    or to_regclass('public.blocks') is null
    or to_regclass('public.ballots') is null
    or to_regclass('public.votes') is null
    or to_regclass('public.audit_logs') is null
    or to_regprocedure('public.pgcrypto_crypt(text,text)') is null
    or to_regprocedure('public.pgcrypto_gen_salt(text)') is null
    or to_regprocedure('public.pgcrypto_random_bytes(integer)') is null
    or to_regprocedure('public.pgcrypto_random_uuid()') is null
    or to_regprocedure('public.pgcrypto_digest(text,text)') is null
    or to_regprocedure('public.get_candidate_results_safe()') is null
    or to_regprocedure('public.get_election_stats_safe()') is null
    or to_regprocedure('public.get_public_receipts_safe()') is null
    or to_regprocedure('public.get_voter_ballot_status_safe(uuid,uuid)') is null
    or to_regprocedure('public.register_voter(text,text,text,text,text,uuid)') is null
    or to_regprocedure('public.check_voter_duplicate(text,text,uuid)') is null
    or to_regprocedure('public.check_candidate_application_duplicate(uuid,uuid,text,text)') is null
    or to_regprocedure('public.get_voter_login_by_email(text)') is null
    or to_regprocedure('public.verify_voter_password(text,text)') is null
    or to_regprocedure('public.change_voter_password(uuid,text,text)') is null
    or to_regprocedure('public.cast_ballot(text,text,text,jsonb)') is null
    or to_regprocedure('public.update_current_election_settings(text,text,timestamptz,timestamptz)') is null
    or to_regprocedure('public.reset_current_election_data()') is null
    or to_regprocedure('public.delete_voter(uuid)') is null
    or to_regprocedure('public.delete_candidate(uuid)') is null
    or to_regprocedure('public.delete_candidate_application(uuid)') is null
  then
    raise exception 'Run supabase/reset_wucc_evoting.sql before seed.sql.';
  end if;
end $$;

-- Election ---------------------------------------------------------

insert into public.elections (title, status, ledger_status, starts_at, ends_at)
select 'WUCC', 'standby'::public.election_status, 'open', now() + interval '15 minutes', now() + interval '8 hours'
where not exists (select 1 from public.elections);

update public.elections e
set title = 'WUCC',
    status = case
      when e.status::text in ('inactive', 'standby', 'active', 'ended', 'finalized') then e.status
      else 'standby'::public.election_status
    end,
    ledger_status = case
      when e.status::text = 'finalized' then 'finalized'
      when e.status::text = 'ended' then 'ready_to_finalize'
      when e.status::text = 'inactive' then 'locked'
      else 'open'
    end,
    starts_at = coalesce(e.starts_at, now() + interval '15 minutes'),
    ends_at = coalesce(e.ends_at, now() + interval '8 hours'),
    updated_at = now()
where e.id = (select latest_election.id from public.elections latest_election order by latest_election.created_at desc limit 1);

-- Positions --------------------------------------------------------

with current_election as (
  select e.id from public.elections e order by e.created_at desc limit 1
),
canonical(slug, title, icon, display_order) as (
  values
    ('governor', 'Governor', 'shield', 1),
    ('deputy-governor', 'Deputy Governor', 'medal', 2),
    ('gsec', 'General Secretary', 'clipboard', 3),
    ('agsec', 'Assistant General Secretary', 'file-text', 4),
    ('fsec', 'Financial Secretary', 'wallet', 5),
    ('pro', 'Public Relations Officer', 'megaphone', 6),
    ('dwelfare', 'Director of Welfare', 'heart-handshake', 7),
    ('dhealth', 'Director of Health', 'cross', 8),
    ('dsport', 'Director of Sports', 'trophy', 9),
    ('dsocials', 'Director of Socials', 'sparkles', 10)
)
insert into public.positions (election_id, slug, title, icon, display_order, is_active)
select current_election.id, canonical.slug, canonical.title, canonical.icon, canonical.display_order, true
from current_election
cross join canonical
on conflict (election_id, slug) do update set
  title = excluded.title,
  icon = excluded.icon,
  display_order = excluded.display_order,
  is_active = true,
  updated_at = now();

