    ('governor', 'Emeka Okafor', 'COSC/21045', 'Computer Science', '300L', 'emeka@votechain.local', '08010000001', 4.42, 'Build a transparent, digital-first WUCC administration.', array['Transparent reports', 'Student tech hub', 'Digital support desk']::text[], 'Class representative', 'approved'::public.record_status, 'WUCC-APP-GOV-001'),
