    ('deputy-governor', 'Tunde Bakare', 'IT/20445', 'Information Technology', '400L', 'tunde@votechain.local', '08010000004', 4.20, 'Connect students to projects, internships, and industry.', array['Project funding', 'Industry linkages', 'Internship portal']::text[], 'Project coordinator', 'approved'::public.record_status, 'WUCC-APP-DGOV-002'),
