    ('pro', 'Sarah Ibekwe', 'CYB/22014', 'Cybersecurity', '200L', 'sarah@votechain.local', '08010000007', 4.31, 'Make WUCC announcements clear, timely, and accessible.', array['Better publicity', 'Event calendar', 'Student feedback']::text[], 'Media volunteer', 'rejected'::public.record_status, 'WUCC-APP-PRO-001')
