insert into public.candidate_applications (
  election_id,
  position_id,
  full_name,
  matric,
  department,
  level,
  email,
  phone,
  manifesto,
  promises,
  cgpa,
  previous_role,
  status,
  reference,
  photo_url
)
select
  current_election.id,
  p.id,
  apps.full_name,
  upper(apps.matric),
  apps.department,
  apps.level,
  lower(apps.email),
  apps.phone,
  apps.manifesto,
  apps.promises,
  apps.cgpa,
  apps.previous_role,
  apps.status,
  apps.reference,
  null
from apps
join current_election on true
join public.positions p on p.election_id = current_election.id and p.slug = apps.slug
on conflict (election_id, position_id, matric) do update set
  full_name = excluded.full_name,
  department = excluded.department,
  level = excluded.level,
  email = excluded.email,
  phone = excluded.phone,
  manifesto = excluded.manifesto,
  promises = excluded.promises,
  cgpa = excluded.cgpa,
  previous_role = excluded.previous_role,
  status = excluded.status,
  reference = excluded.reference,
  updated_at = now();

-- Approved application candidates --------------------------------

insert into public.candidates (
  election_id,
  position_id,
  application_id,
  full_name,
  matric,
  email,
  department,
  level,
  cgpa,
  manifesto,
  promises,
  photo_url,
  status
)
select
  app.election_id,
  app.position_id,
  app.id,
  app.full_name,
  app.matric,
  app.email,
  app.department,
  app.level,
  app.cgpa,
  app.manifesto,
  app.promises,
  app.photo_url,
  'approved'
from public.candidate_applications app
where app.status = 'approved'
on conflict (election_id, position_id, matric) do update set
  application_id = excluded.application_id,
  full_name = excluded.full_name,
  email = excluded.email,
  department = excluded.department,
  level = excluded.level,
  cgpa = excluded.cgpa,
  manifesto = excluded.manifesto,
  promises = excluded.promises,
  photo_url = excluded.photo_url,
  status = 'approved',
  updated_at = now();

-- Manual/seed-only candidates ensure every office is visible in admin
-- and Vote/Results have approved ballot options after a fresh install.

