    ('gsec', 'Daniel Iro', 'IT/21022', 'daniel@votechain.local', 'Information Technology', '300L', 4.09, 'Keep communication concise, traceable, and timely.', array['Meeting minutes', 'Academic reminders', 'Digital forms']::text[], 'avatar'),
    ('agsec', 'Mariam Bello', 'CYB/22018', 'mariam@votechain.local', 'Cybersecurity', '200L', 4.01, 'Make assistant secretarial support more responsive.', array['Notice templates', 'Class feedback', 'Document support']::text[], 'avatar'),
    ('fsec', 'David Mensah', 'IT/21119', 'david@votechain.local', 'Information Technology', '300L', 4.05, 'Keep WUCC finances accountable and easy to understand.', array['Monthly reports', 'Transparent dues', 'Budget dashboard']::text[], 'avatar'),
    ('pro', 'Sarah Ibekwe', 'CYB/22014', 'sarah@votechain.local', 'Cybersecurity', '200L', 4.31, 'Make WUCC announcements clear, timely, and accessible.', array['Better publicity', 'Event calendar', 'Student feedback']::text[], 'avatar'),
    ('dwelfare', 'Kelvin Musa', 'SWE/21028', 'kelvin@votechain.local', 'Software Engineering', '300L', 4.18, 'Prioritize student welfare and responsive support.', array['Welfare desk', 'Emergency support', 'Peer mentoring']::text[], 'avatar'),
    ('dhealth', 'Nora Etim', 'COSC/22031', 'nora@votechain.local', 'Computer Science', '200L', 4.27, 'Promote health awareness and campus wellness.', array['Health drives', 'Wellness talks', 'First-aid readiness']::text[], 'avatar'),
