-- Demo blockchain ledger -----------------------------------------
-- Two deterministic PBFT-confirmed demo ballots. They use hashes only
-- in public ledger views; voter identity remains private behind RLS/RPC.

with current_election as (
  select e.id from public.elections e order by e.created_at desc limit 1
),
demo_ballots(matric, block_number, tx_hash, vote_hash, receipt_hash, block_hash, voter_hash, previous_hash) as (
  values
    ('COSC/21045', 1201::bigint, '0xseedtx000000000000000000000000000000000000000000000000000000000001', '0xseedvote000000000000000000000000000000000000000000000000000000001', '0xseedreceipt000000000000000000000000000000000000000000000000000001', '0xseedblock000000000000000000000000000000000000000000000000000001', '0xseedvoter000001', null::text),
    ('CYB/21007', 1202::bigint, '0xseedtx000000000000000000000000000000000000000000000000000000000002', '0xseedvote000000000000000000000000000000000000000000000000000000002', '0xseedreceipt000000000000000000000000000000000000000000000000000002', '0xseedblock000000000000000000000000000000000000000000000000000002', '0xseedvoter000002', '0xseedblock000000000000000000000000000000000000000000000000000001')
),
inserted_blocks as (
  insert into public.blocks (
    election_id,
    voter_id,
    block_number,
    tx_hash,
    vote_hash,
    receipt_hash,
    block_hash,
    voter_hash,
    previous_hash,
    validator_status,
    validation_status,
    consensus_status,
    validator_confirmations,
    confirmation_count
  )
  select
    current_election.id,
    v.id,
    demo_ballots.block_number,
    demo_ballots.tx_hash,
    demo_ballots.vote_hash,
    demo_ballots.receipt_hash,
    demo_ballots.block_hash,
    demo_ballots.voter_hash,
    demo_ballots.previous_hash,
    'pbft_confirmed',
    'pbft_confirmed',
    'confirmed',
    4,
    4
  from demo_ballots
  join current_election on true
  join public.voters v on upper(v.matric) = upper(demo_ballots.matric)
  on conflict (tx_hash) do update set
    vote_hash = excluded.vote_hash,
    receipt_hash = excluded.receipt_hash,
    block_hash = excluded.block_hash,
    validation_status = 'pbft_confirmed',
    consensus_status = 'confirmed'
  returning id, election_id, voter_id, block_number, tx_hash, vote_hash, receipt_hash, block_hash, previous_hash, voter_hash, validation_status, created_at
),
inserted_ballots as (
  insert into public.ballots (
    election_id,
    voter_id,
    block_id,
    block_number,
    tx_hash,
    vote_hash,
    receipt_hash,
    block_hash,
    previous_hash,
    voter_hash,
    validator_status,
    validation_status,
    consensus_status,
    validator_confirmations,
    confirmation_count
  )
  select
    election_id,
    voter_id,
    id,
    block_number,
    tx_hash,
    vote_hash,
    receipt_hash,
    block_hash,
    previous_hash,
    voter_hash,
    'pbft_confirmed',
    'pbft_confirmed',
    'confirmed',
    4,
    4
  from inserted_blocks
  on conflict (tx_hash) do update set
    vote_hash = excluded.vote_hash,
    receipt_hash = excluded.receipt_hash,
    block_hash = excluded.block_hash,
    validation_status = 'pbft_confirmed',
    consensus_status = 'confirmed'
  returning id, election_id, voter_id, block_id, receipt_hash, block_hash
),
first_candidates as (
  select distinct on (c.election_id, c.position_id)
    c.election_id,
    c.position_id,
    c.id as candidate_id
  from public.candidates c
  where c.status = 'approved'
  order by c.election_id, c.position_id, c.created_at asc
)
insert into public.votes (
  election_id,
  ballot_id,
  block_id,
  voter_id,
  position_id,
  candidate_id,
  vote_hash,
  receipt_hash,
  block_hash,
  validation_status,
  consensus_status
)
select
  b.election_id,
  b.id,
  b.block_id,
  b.voter_id,
  fc.position_id,
  fc.candidate_id,
  '0x' || encode(public.pgcrypto_digest(b.receipt_hash || ':' || fc.position_id::text || ':' || fc.candidate_id::text, 'sha256'), 'hex'),
  b.receipt_hash,
  b.block_hash,
  'pbft_confirmed',
  'confirmed'
from inserted_ballots b
join first_candidates fc on fc.election_id = b.election_id
on conflict (election_id, voter_id, position_id) do update set
  candidate_id = excluded.candidate_id,
  vote_hash = excluded.vote_hash,
  receipt_hash = excluded.receipt_hash,
  block_hash = excluded.block_hash,
  validation_status = 'pbft_confirmed',
  consensus_status = 'confirmed';

update public.voters v
set has_voted = true,
    updated_at = now()
where upper(v.matric) in ('COSC/21045', 'CYB/21007');

commit;
